SELECT genome_name
FROM genomes
ORDER BY sequence_length DESC;

SELECT genome_name 
FROM genomes 
WHERE sequence_length = (SELECT MAX(sequence_length) FROM genomes);

SELECT AVG(num_features) AS avg_features
FROM (
    SELECT COUNT(DISTINCT feature_id) AS num_features
    FROM features
    GROUP BY genome_id
);

SELECT genome_id, genome_name, accession 
FROM genomes 
WHERE genome_id = 0 AND sequence_length = 566;

SELECT COUNT(*)
FROM proteins
WHERE function = 'AMP-dependent synthetase/ligase in alkane synthesis cluster';

SELECT COUNT(*)
FROM annotations
INNER JOIN features ON annotations.feature_id = features.feature_id;

SELECT feature_type_name
FROM feature_types
WHERE feature_type_name = 'gene';

SELECT gene_symbol_id, symbol_name, description, gene_symbol_type 
FROM gene_symbols 
WHERE feature_id = 1;
